const TZ = 'America/Argentina/Buenos_Aires';

function parseYMD(value) {
  if (!value || typeof value !== 'string') return null;
  const m = value.trim().match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!m) return null;
  return new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]), 0, 0, 0, 0);
}

function nowInTimezone(timeZone) {
  return new Date(new Date().toLocaleString('en-US', { timeZone }));
}

function startOfDay(d) {
  const x = new Date(d);
  x.setHours(0, 0, 0, 0);
  return x;
}

function daysBetween(a, b) {
  const ms = 24 * 60 * 60 * 1000;
  return Math.floor((b.getTime() - a.getTime()) / ms);
}

function toBool(v) {
  if (typeof v === 'boolean') return v;
  if (typeof v === 'number') return v !== 0;
  if (typeof v !== 'string') return false;
  return ['true', '1', 'si', 'sÃ­', 'yes', 'y', 'x'].includes(v.trim().toLowerCase());
}

function buildRegex(pattern, fallbackName) {
  if (pattern && typeof pattern === 'string') {
    try {
      return new RegExp(pattern, 'i');
    } catch (_) {}
  }

  const safe = String(fallbackName || '')
    .trim()
    .replace(/[.*+?^${}()|[\]\\]/g, '\$&')
    .replace(/\s+/g, '.*');

  return safe ? new RegExp(safe, 'i') : null;
}

const today = startOfDay(nowInTimezone(TZ));
const runMode = $input.first()?.json?.run_mode || 'scheduled';
const runCorrelation = `ak-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

const actionable = [];

for (const item of items) {
  const row = item.json;
  const status = String(row.Status_Contrato || '').trim().toLowerCase();
  const isActiveContract = ['activo', 'active', 'activa'].includes(status);
  if (!isActiveContract) continue;

  const endDate = parseYMD(row.Fecha_Fin);
  if (!endDate) continue;

  const diffDays = daysBetween(today, endDate);
  const isExpired = diffDays <= 0;
  const isPreventiveWindow = diffDays >= 0 && diffDays <= 2;
  const alreadyNotified = toBool(row.Notificado_Previo);

  const adName = String(row.Ad_Name || row.Ad_Name_Meta || row.Nombre_Anuncio || '').trim();
  const regex = buildRegex(row.Regex_Anuncio || row.Regex_Anuncio, adName);
  const regexMatchesSheetName = regex ? regex.test(adName) : false;

  let controlType = null;
  if (isExpired) controlType = 'expired';
  else if (isPreventiveWindow && !alreadyNotified) controlType = 'preventive';

  if (!controlType) continue;

  actionable.push({
    json: {
      ...row,
      run_mode: runMode,
      correlation_id: runCorrelation,
      control_type: controlType,
      days_to_end: diffDays,
      timezone: TZ,
      regex_pattern: regex ? regex.source : null,
      regexMatchesSheetName
    }
  });
}

return actionable;

function normalize(row, fallback = {}) {
  const normalized = { ...row };
  normalized.Contrato_ID = String(normalized.Contrato_ID ?? fallback.Contrato_ID ?? '').trim();
  normalized.Fecha_Fin = String(normalized.Fecha_Fin ?? fallback.Fecha_Fin ?? '').trim();

  const regexCanon = String(normalized.Regex_Anuncio ?? normalized.regex_pattern ?? fallback.Regex_Anuncio ?? fallback.regex_pattern ?? '').trim();
  normalized.Regex_Anuncio = regexCanon;
  normalized.regex_pattern = String(normalized.regex_pattern ?? regexCanon).trim();

  return normalized;
}

